create table if not exists public.multichannel_executive_reports(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id)on delete cascade,period_type text not null check(period_type in('day','week','month')),period_start date not null,period_end date not null,payload jsonb not null,source_hash text not null check(source_hash~'^[a-f0-9]{64}$'),status text not null default'ready'check(status in('ready','reviewed','superseded')),generated_by uuid not null references public.profiles(id),reviewed_by uuid references public.profiles(id),review_reason text,reviewed_at timestamptz,created_at timestamptz not null default now(),check(period_end>=period_start),unique(organization_id,period_type,period_start,source_hash));create index if not exists multichannel_reports_org_idx on public.multichannel_executive_reports(organization_id,period_end desc,period_type);alter table public.multichannel_executive_reports enable row level security;create policy multichannel_reports_leadership_read on public.multichannel_executive_reports for select to authenticated using(organization_id=(select public.current_organization_id())and exists(select 1 from public.profiles p where p.id=auth.uid()and coalesce(p.commercial_role,case when p.role='admin'then'director'else p.role end)in('director','superintendent')));revoke all on public.multichannel_executive_reports from anon,authenticated;grant select on public.multichannel_executive_reports to authenticated;
create or replace function public.review_multichannel_executive_report(p_actor_id uuid,p_organization_id uuid,p_report_id uuid,p_reason text)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$declare v_id uuid;begin if not exists(select 1 from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true and coalesce(commercial_role,case when role='admin'then'director'else role end)='director')then raise exception'report_director_required';end if;if char_length(trim(coalesce(p_reason,'')))<20 then raise exception'report_reason_required';end if;update public.multichannel_executive_reports set status='reviewed',reviewed_by=p_actor_id,review_reason=trim(p_reason),reviewed_at=now()where id=p_report_id and organization_id=p_organization_id and status='ready'returning id into v_id;if v_id is null then raise exception'report_not_reviewable';end if;return jsonb_build_object('reportId',v_id,'status','reviewed','automaticDecision',false);end$$;revoke all on function public.review_multichannel_executive_report(uuid,uuid,uuid,text)from public,anon,authenticated;grant execute on function public.review_multichannel_executive_report(uuid,uuid,uuid,text)to service_role;
